using System.Collections;
using UnityEngine;

/// <summary>Para onde Action_FocusCamera direciona a câmara.</summary>
public enum CameraFocusMode
{
    /// <summary>Foca neste NPC (a câmara segue-o, se ele se mover — ex: durante uma fala com movimento).</summary>
    Npc,

    /// <summary>Segue "target" (acompanha se "target" se mover — ex: um boss, outro NPC).</summary>
    Target,

    /// <summary>Fixa a câmara na posição actual de "target" (snapshot — não acompanha movimento posterior).</summary>
    Point
}

/// <summary>
/// Direciona a câmara (via CameraManager) para um ponto de interesse durante
/// uma cutscene — ex: focar no NPC que está a falar, seguir um boss, ou olhar
/// para um marco fixo da cena. Usar Action_ReleaseCamera no fim para devolver
/// o controlo à câmara automática do player.
/// </summary>
[System.Serializable]
public class Action_FocusCamera : NpcAction
{
    public CameraFocusMode mode = CameraFocusMode.Npc;

    [Tooltip("Usado quando Mode = Target ou Point.")]
    public Transform target;

    [Tooltip("Tempo de espera (segundos) após mudar o foco, para dar tempo ao blend da câmara antes da próxima ação (ex: antes de uma fala). 0 = não espera.")]
    public float waitTime = 0f;

    public override IEnumerator Execute(NpcController npc)
    {
        var cam = CameraManager.Instance;
        if (cam == null) yield break;

        switch (mode)
        {
            case CameraFocusMode.Npc:
                cam.EnterManualFollow(npc.transform);
                break;

            case CameraFocusMode.Target:
                if (target != null) cam.EnterManualFollow(target);
                break;

            case CameraFocusMode.Point:
                if (target != null) cam.EnterManualLock(target.position);
                break;
        }

        if (waitTime > 0f) yield return NpcActionUtil.Wait(waitTime);
    }
}

/// <summary>
/// Devolve o controlo da câmara ao modo automático (segue o player, zoom
/// dinâmico, etc.) — usar no fim de uma cutscene iniciada com Action_FocusCamera.
/// </summary>
[System.Serializable]
public class Action_ReleaseCamera : NpcAction
{
    [Tooltip("Tempo de espera (segundos) após devolver a câmara ao player, para dar tempo ao blend. 0 = não espera.")]
    public float waitTime = 0f;

    public override IEnumerator Execute(NpcController npc)
    {
        CameraManager.Instance?.ExitManual();
        if (waitTime > 0f) yield return NpcActionUtil.Wait(waitTime);
    }
}

/// <summary>
/// Aplica um abanão (shake) de câmara — útil para impactos, explosões, a
/// chegada de um boss, etc. Aplica-se à vcam realmente activa no momento
/// (incluindo durante um Action_FocusCamera).
/// </summary>
[System.Serializable]
public class Action_ShakeCamera : NpcAction
{
    [Tooltip("Intensidade do abanão.")]
    public float amplitude = 1.5f;

    [Tooltip("Velocidade de oscilação do abanão.")]
    public float frequency = 2f;

    [Tooltip("Duração do abanão, em segundos.")]
    public float duration = 0.3f;

    [Tooltip("Se activo, espera a duração do abanão terminar antes de avançar para a próxima ação.")]
    public bool waitForShake;

    public override IEnumerator Execute(NpcController npc)
    {
        CameraManager.Instance?.Shake(amplitude, frequency, duration);
        if (waitForShake && duration > 0f) yield return NpcActionUtil.Wait(duration);
    }
}
